module top_module(input signed [7:0] a, b, output reg signed [7:0] sub_result, sub_out, mul_out, div_out, output reg [1:0] op);always @ (a, b, op) begin
        case (op)
            2'b00: begin // addition
                sub_result = a + b;
                sub_out = 0;
                mul_out = 0;
                div_out = 0;
            end
            2'b01: begin // subtraction
                sub_result = 0;
                sub_out = a - b;
                mul_out = 0;
                div_out = 0;
            end
            2'b10: begin // multiplication
                sub_result = 0;
                sub_out = 0;
                mul_out = a * b;
                div_out = 0;
            end
            2'b11: begin // division
                sub_result = 0;
                sub_out = 0;
                mul_out = 0;
                div_out = (b != 0) ? (a / b) : 0; // handle division by zero
            end
            default: begin
                sub_result = 0;
                sub_out = 0;
                mul_out = 0;
                div_out = 0;
            end
        endcase
    end

endmodule
